// AI Gateway proxy — sits between holocron docs sites and Cloudflare Workers AI.
//
// Exposes an OpenAI-compatible /v1/chat/completions endpoint. User sites call
// this with `@ai-sdk/openai-compatible`. The proxy runs inference via the
// native AI binding (env.AI — no HTTP hop, no API token needed) and streams
// the response back in OpenAI SSE format.
//
// The Env type (including AI: Ai) is generated by `wrangler types` into
// worker-configuration.d.ts. Rerun `wrangler types` after changing wrangler.jsonc.
//
// MVP: no auth, no usage tracking — all requests are allowed through.
// TODO comments mark where auth, billing, and rate limiting will go.

import { Spiceflow } from 'spiceflow'
import { env } from 'cloudflare:workers'
import { createWorkersAI } from 'workers-ai-provider'
import { streamText } from 'ai'

const CF_AI_MODEL = '@cf/zai-org/glm-4.7-flash' as const

export const gatewayApp = new Spiceflow()

  // ── OpenAI-compatible chat completions proxy ───────────────────────────
  .post('/api/ai/v1/chat/completions', async ({ request }) => {
    // TODO: Extract and validate holo_xxx API key from Authorization header
    // const apiKey = extractApiKey(request)
    // if (!apiKey) return new Response(JSON.stringify({ error: 'Missing API key' }), { status: 401 })
    // const record = await kv.getApiKey(apiKey)
    // if (!record) return new Response(JSON.stringify({ error: 'Invalid API key' }), { status: 401 })

    // TODO: Check spending cap / rate limit
    // if (record.dollarsUsed >= record.spendingCap) {
    //   return new Response(JSON.stringify({ error: 'Spending limit reached' }), { status: 402 })
    // }

    const body = (await request.json()) as {
      model?: string
      messages?: Array<{ role: string; content: string }>
      stream?: boolean
      temperature?: number
      max_tokens?: number
      tools?: unknown[]
      tool_choice?: unknown
    }

    // env.AI is typed from worker-configuration.d.ts (generated by `wrangler types`)
    const workersai = createWorkersAI({ binding: env.AI })

    // TODO: Pass gateway options for analytics/caching when AI Gateway is set up
    // const workersai = createWorkersAI({
    //   binding: env.AI,
    //   gateway: { id: 'holocron', skipCache: false, cacheTtl: 3360 },
    // })

    const result = streamText({
      model: workersai(CF_AI_MODEL),
      messages: (body.messages || []).map((m) => ({
        role: m.role as 'system' | 'user' | 'assistant',
        content: m.content,
      })),
      temperature: body.temperature,
      maxOutputTokens: body.max_tokens,
      // TODO: Forward tools if the model supports function calling
      // tools: body.tools,
    })

    // TODO: After stream completes, extract token usage and deduct from spending cap
    // const usage = await result.usage
    // await kv.incrementUsage(apiKey, calculateCost(usage))

    // Return OpenAI-compatible streaming response with CORS headers
    return result.toTextStreamResponse({
      headers: {
        'access-control-allow-origin': '*',
        'access-control-allow-headers': 'authorization, content-type',
        'content-type': 'text/event-stream',
        'content-encoding': 'identity',
        'transfer-encoding': 'chunked',
      },
    })
  })

  // ── CORS preflight for the AI proxy ────────────────────────────────────
  .get('/api/ai/v1/chat/completions', () => {
    return new Response(null, {
      status: 204,
      headers: {
        'access-control-allow-origin': '*',
        'access-control-allow-methods': 'POST, OPTIONS',
        'access-control-allow-headers': 'authorization, content-type',
      },
    })
  })

